        int t;
        for (int i = 0; i < mas.length; i++) {
            for (int j = i + 1; j < mas.length; j++) {
                if (mas[j] < mas[i]) {
                    t = mas[i];
                    mas[i] = mas[j];
                    mas[j] = t;
                }
            }
        }
        for (int i = 0; i < mas.length; i++) {

            for (int k = i; k > 0; k--) {
