	public Process activeProcess() {
		if(index >= list.size()) index = 0;
		if(list.get(index).getremaining() == 1 || remainingDelta == 0)
		{
			remainingDelta = deltaTime;
			index++;
		}
		if(index >= list.size()) index = 0;
		remainingDelta--;
		return list.get(index);

